return-response.set-body:
@{
        var prm = new JObject
        {
          ["resource"] = "https://${apim_name}.azure-api.net/mcp/${mcp_server_name}",
          ["authorization_servers"] = new JArray
          {
            $"https://login.microsoftonline.com/${tenant_id}/v2.0"
          },
          ["scopes_supported"] = new JArray { "api://${obo_client_id}/Mcp.Access" },
          ["bearer_methods_supported"] = new JArray { "header" },
          ["resource_documentation"] = $"https://{context.Request.OriginalUrl.Host}/docs",
          ["mcp_protocol_version"] = "2025-11-25"
        };
        return prm.ToString();
      }
